2997 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
2998                                                FPClassTest DemandedMask,
2999                                                KnownFPClass &Known,
3000                                                unsigned Depth) {
3001   Use &U = I->getOperandUse(OpNo);
3002   Value *V = U.get();
3003   Type *VTy = V->getType();
3004 
3005   if (DemandedMask == fcNone) {
3006     if (isa<UndefValue>(V))
3007       return false;
3008     replaceUse(U, PoisonValue::get(VTy));
3009     return true;
3010   }
3011 
3012   // Handle constant
3013   Instruction *VInst = dyn_cast<Instruction>(V);
3014   if (!VInst) {
3015     // Handle constants and arguments
3016     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3017 
3018     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
3019     if (ValidResults == fcNone) {
3020       if (isa<UndefValue>(V))
3021         return false;
3022       replaceUse(U, PoisonValue::get(VTy));
3023       return true;
3024     }
3025 
3026     // Do not try to replace values which are already constants (unless we are
3027     // folding to poison). Doing so could promote poison elements to non-poison
3028     // constants.
3029     if (isa<Constant>(V))
3030       return false;
3031 
3032     Value *FoldedToConst = getFPClassConstant(VTy, ValidResults);
3033     if (!FoldedToConst || FoldedToConst == V)
3034       return false;
3035 
3036     replaceUse(U, FoldedToConst);
3037     return true;
3038   }
3039 
3040   if (Depth == MaxAnalysisRecursionDepth)
3041     return false;
3042 
3043   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3044     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3045     DemandedMask &= ~NoFPClass;
3046   }
3047 
3048   Value *NewVal;
3049 
3050   if (VInst->hasOneUse()) {
3051     // If the instruction has one use, we can directly simplify it.
3052     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3053   } else {
3054     // If there are multiple uses of this instruction, then we can simplify
3055     // VInst to some other value, but not modify the instruction.
3056     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3057                                                 Depth);
3058   }
3059 
3060   if (!NewVal)
3061     return false;
3062   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3063     salvageDebugInfo(*OpInst);
3064 
3065   replaceUse(U, NewVal);
3066   return true;
3067 }
