444   if (paramHasAttr(ArgNo, Attribute::Dereferenceable) &&
445       !NullPointerIsDefined(
446           getCaller(),
447           getArgOperand(ArgNo)->getType()->getPointerAddressSpace()))
448     return true;
449 
450   return false;
